package main

import (
  "context"
  "fmt"
  "time"

  clientv3 "go.etcd.io/etcd/client/v3"
)

func main() {
  cli, _ := clientv3.New(clientv3.Config{Endpoints: []string{"localhost:2379"}})
  defer cli.Close()
  ctx := context.Background()

  // 1. Create a lease with 10s TTL
  leaseResp, _ := cli.Grant(ctx, 10)
  leaseID := leaseResp.ID

  // 2. Put a key with the lease
  _, err := cli.Put(ctx, "/locks/orders/123", "clientA", clientv3.WithLease(leaseID))
  if err != nil {
    panic(err)
  }
  fmt.Println("Lock acquired")

  // 3. Keep the lease alive in background
  ch, _ := cli.KeepAlive(ctx, leaseID)
  go func() {
    for ka := range ch {
      fmt.Println("Lease keepalive received", ka)
    }
  }()

  // simulate work
  time.Sleep(5 * time.Second)

  // 4. Revoke lease to release lock
  cli.Revoke(ctx, leaseID)
  fmt.Println("Lock released")
}
